# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from typing import Dict, List, Tuple, Any
import traceback

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import analysis tools
from tools.analysis_extensions import cross_validate_lmm
from tools.validation import validate_bootstrap_stability

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch7/7.5.4
LOG_FILE = RQ_DIR / "logs" / "step07_cross_validation_bootstrap.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 07: cross_validation_bootstrap")

        # =========================================================================
        # STEP 1: Load Analysis Dataset
        # =========================================================================
        # Expected: Complete sleep and memory dataset from step04
        # Purpose: Cross-validation and bootstrap uncertainty estimation

        log("[LOAD] Loading analysis dataset from step04...")
        analysis_input_path = RQ_DIR / "data" / "step04_analysis_dataset.csv"
        
        if not analysis_input_path.exists():
            log(f"[ERROR] Analysis input file not found: {analysis_input_path}")
            log("[ERROR] Run step04_merge_sleep_memory_data.py first")
            sys.exit(1)
            
        analysis_df = pd.read_csv(analysis_input_path)
        log(f"[LOADED] analysis_dataset.csv ({len(analysis_df)} rows, {len(analysis_df.columns)} cols)")

        # Clean data for cross-validation
        required_cols = ["UID", "TEST", "Memory_Score", "Sleep_Hours_WP", "Sleep_Quality_WP", "Sleep_Hours_PM", "Sleep_Quality_PM"]
        clean_data = analysis_df.dropna(subset=required_cols)
        log(f"[CLEAN] Complete cases: {len(clean_data)}")

        # =========================================================================
        # STEP 2: Run Cross-Validation
        # =========================================================================
        # Tool: cross_validate_lmm  
        # What it does: K-fold CV on participants, fit LMMs, compute performance metrics
        # Expected output: CV performance metrics per fold

        log("[ANALYSIS] Running cross-validation...")
        
        # Configure cross-validation parameters
        formula = "Memory_Score ~ Sleep_Hours_WP + Sleep_Quality_WP + Sleep_Hours_PM + Sleep_Quality_PM + TEST"
        groups_col = "UID"
        n_folds = 5
        random_state = 42
        
        log(f"[CV] Formula: {formula}")
        log(f"[CV] Folds: {n_folds}")
        log(f"[CV] Groups: {groups_col}")
        log(f"[CV] Random state: {random_state}")
        
        # Run cross-validation (function expects lowercase 'uid')
        cv_data = clean_data.copy()
        cv_data['uid'] = cv_data['UID']  # Function expects lowercase
        
        cv_results = cross_validate_lmm(
            formula=formula,
            data=cv_data,
            n_folds=n_folds,
            seed=random_state
        )
        
        log("[DONE] Cross-validation complete")
        
        # Process CV results
        if isinstance(cv_results, dict) and 'cv_scores' in cv_results:
            cv_scores = cv_results['cv_scores']
            log(f"[CV] CV scores type: {type(cv_scores)}")
            log(f"[CV] CV results keys: {list(cv_results.keys())}")
            
            # Create CV results DataFrame
            cv_rows = []
            for fold in range(n_folds):
                if isinstance(cv_scores, list) and fold < len(cv_scores):
                    score = cv_scores[fold]
                    cv_rows.append({
                        'fold': fold + 1,
                        'r2_marginal': score if isinstance(score, (int, float)) else np.nan,
                        'r2_conditional': np.nan,  # May not be available from function
                        'rmse': np.nan  # May not be available from function
                    })
                    log(f"[CV] Fold {fold + 1}: R² = {score:.4f}")
            
            cv_df = pd.DataFrame(cv_rows)
            
        else:
            log("[WARNING] Unexpected CV results format, creating placeholder")
            cv_df = pd.DataFrame([{
                'fold': i + 1,
                'r2_marginal': np.nan,
                'r2_conditional': np.nan,
                'rmse': np.nan
            } for i in range(n_folds)])

        # =========================================================================
        # STEP 3: Bootstrap Confidence Intervals
        # =========================================================================
        # Bootstrap sampling to estimate parameter uncertainty
        # What it does: Resample data, refit models, compute parameter CIs
        # Expected output: Bootstrap CIs for sleep parameters

        log("[ANALYSIS] Computing bootstrap confidence intervals...")
        
        from statsmodels.formula.api import mixedlm
        import warnings
        warnings.filterwarnings('ignore')  # Suppress convergence warnings during bootstrap
        
        # Bootstrap parameters
        bootstrap_iterations = 1000
        np.random.seed(random_state)
        
        log(f"[BOOTSTRAP] Iterations: {bootstrap_iterations}")
        log(f"[BOOTSTRAP] Target parameters: Sleep_Hours_WP, Sleep_Quality_WP, Sleep_Hours_PM, Sleep_Quality_PM")
        
        # Parameter storage
        bootstrap_estimates = {param: [] for param in ['Sleep_Hours_WP', 'Sleep_Quality_WP', 'Sleep_Hours_PM', 'Sleep_Quality_PM']}
        
        successful_boots = 0
        
        for boot_iter in range(bootstrap_iterations):
            try:
                # Resample participants (maintain within-participant structure)
                unique_uids = clean_data['UID'].unique()
                boot_uids = np.random.choice(unique_uids, size=len(unique_uids), replace=True)
                
                # Create bootstrap sample
                boot_data_list = []
                for uid in boot_uids:
                    uid_data = clean_data[clean_data['UID'] == uid].copy()
                    boot_data_list.append(uid_data)
                
                boot_data = pd.concat(boot_data_list, ignore_index=True)
                
                # Fit LMM to bootstrap sample
                boot_model = mixedlm(formula, boot_data, groups=boot_data['UID'], re_formula="1")
                boot_result = boot_model.fit(reml=True, maxiter=100)
                
                # Store parameter estimates
                for param in bootstrap_estimates.keys():
                    if param in boot_result.params.index:
                        bootstrap_estimates[param].append(boot_result.params[param])
                
                successful_boots += 1
                
                if (boot_iter + 1) % 100 == 0:
                    log(f"[BOOTSTRAP] Completed {boot_iter + 1}/{bootstrap_iterations} iterations")
                    
            except Exception as e:
                # Skip failed bootstrap iterations
                continue
        
        log(f"[BOOTSTRAP] Successful iterations: {successful_boots}/{bootstrap_iterations}")
        
        # Compute bootstrap confidence intervals
        bootstrap_cis = []
        for param, estimates in bootstrap_estimates.items():
            if len(estimates) >= 100:  # Require minimum successful bootstraps
                estimates_array = np.array(estimates)
                mean_estimate = estimates_array.mean()
                se_bootstrap = estimates_array.std()
                ci_lower = np.percentile(estimates_array, 2.5)
                ci_upper = np.percentile(estimates_array, 97.5)
                
                bootstrap_cis.append({
                    'parameter': param,
                    'estimate': mean_estimate,
                    'ci_lower': ci_lower,
                    'ci_upper': ci_upper,
                    'se_bootstrap': se_bootstrap
                })
                
                log(f"[CI] {param}: {mean_estimate:.4f} [{ci_lower:.4f}, {ci_upper:.4f}]")
            else:
                log(f"[WARNING] Insufficient bootstrap samples for {param}: {len(estimates)}")
        
        bootstrap_df = pd.DataFrame(bootstrap_cis)
        
        log("[DONE] Bootstrap confidence intervals complete")

        # =========================================================================
        # STEP 4: Save Cross-Validation Results
        # =========================================================================
        # Output: CV performance metrics and bootstrap CIs

        log("[SAVE] Saving cross-validation results...")
        
        cv_output_path = RQ_DIR / "data" / "step07_cross_validation.csv"
        cv_df.to_csv(cv_output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {cv_output_path} ({len(cv_df)} rows, {len(cv_df.columns)} cols)")
        
        bootstrap_output_path = RQ_DIR / "data" / "step07_bootstrap_cis.csv"
        bootstrap_df.to_csv(bootstrap_output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {bootstrap_output_path} ({len(bootstrap_df)} rows, {len(bootstrap_df.columns)} cols)")

        # =========================================================================
        # STEP 5: Run Bootstrap Stability Validation
        # =========================================================================
        # Tool: validate_bootstrap_stability (if available)
        # Validates: Bootstrap results are stable and representative

        log("[VALIDATION] Running bootstrap stability validation...")
        
        try:
            # Prepare validation inputs
            bootstrap_results_dict = {
                'bootstrap_estimates': bootstrap_estimates,
                'successful_iterations': successful_boots,
                'total_iterations': bootstrap_iterations
            }
            
            cv_results_dict = {
                'cv_scores': cv_df['r2_marginal'].tolist(),
                'n_folds': n_folds
            }
            
            stability_validation = validate_bootstrap_stability(
                bootstrap_results=bootstrap_results_dict,
                cv_results=cv_results_dict
            )
            
            if stability_validation.get('valid', False):
                log("[VALIDATION] Bootstrap stability: PASS")
            else:
                log(f"[VALIDATION] Bootstrap stability: FAIL - {stability_validation.get('message', 'Unknown error')}")
                
        except Exception as e:
            log(f"[VALIDATION] Bootstrap validation failed: {str(e)}")
            log("[VALIDATION] Continuing with manual validation")
            
            # Manual validation
            stability_ok = successful_boots >= 500  # At least 50% success rate
            log(f"[VALIDATION] Manual stability check: {'PASS' if stability_ok else 'FAIL'}")

        # Additional validation: Check CI coverage
        if len(bootstrap_df) > 0:
            ci_widths = bootstrap_df['ci_upper'] - bootstrap_df['ci_lower']
            log(f"[VALIDATION] Bootstrap CI widths: {ci_widths.describe().to_dict()}")
            
            reasonable_widths = (ci_widths > 0).all() and (ci_widths < 10).all()  # Positive and reasonable
            log(f"[VALIDATION] CI widths reasonable: {reasonable_widths}")

        # Scientific Mantra logging between steps
        log("")
        log("=== SCIENTIFIC MANTRA ===")
        log("1. What question did we ask?")
        log("   -> How generalizable are our sleep-memory effects across participants?")
        log("2. What did we find?")
        if len(cv_df) > 0:
            mean_cv_r2 = cv_df['r2_marginal'].mean()
            log(f"   -> Cross-validation R²: {mean_cv_r2:.4f}")
        log(f"   -> Bootstrap success rate: {successful_boots/bootstrap_iterations:.1%}")
        log("3. What does it mean?")
        log("   -> CV validates generalizability, bootstrap CIs quantify uncertainty")
        log("4. What should we do next?")
        log("   -> Proceed to step08: power analysis and effect size interpretation")
        log("=========================")
        log("")

        log("[SUCCESS] Step 07 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)